ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
CHOICE vague {
  full: { SELECT ?cn ?agn (COUNT(*) AS ?n) WHERE { ?v a :Vaccine ; p:hasAge_Group ?ag ; p:hasHealth_Condition ?hc . ?ag p:name ?agn . ?hc p:condition_name ?cn . } GROUP BY ?cn ?agn }
  component: { SELECT ?agn (COUNT(*) AS ?n) WHERE { ?v a :Vaccine ; p:hasAge_Group ?ag . ?ag p:name ?agn . } GROUP BY ?agn }
  component_2: { SELECT ?cn (COUNT(*) AS ?n) WHERE { ?v a :Vaccine ; p:hasHealth_Condition ?hc . ?hc p:condition_name ?cn . } GROUP BY ?cn }
}
